@page "/shipments"
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments</PageTitle>

<h2>Shipments</h2>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Filter by tracking #, origin, or destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-success" @onclick="ToggleNewForm">
            @(showNewForm ? "Cancel" : "New Shipment")
        </button>
    </div>
</div>

@if (showNewForm)
{
