﻿@page "/"
@inject NavigationManager Navigation

<PageTitle>ShipmentTracker</PageTitle>

<div class="text-center py-5">
    <h1 class="display-4">📦 ShipmentTracker</h1>
    <p class="lead">Track your shipments in real time</p>

    <div class="row justify-content-center mt-4">
        <div class="col-md-6">
            <div class="input-group">
                <input type="text" class="form-control" placeholder="Enter tracking number (e.g. TRK-001-2024)"
                       @bind="trackingNumber" @bind:event="oninput"
                       @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="TrackShipment" disabled="@string.IsNullOrWhiteSpace(trackingNumber)">
                    Track Shipment
                </button>
            </div>
        </div>
    </div>
</div>

@code {
    private string? trackingNumber;

    private void TrackShipment()
    {
        if (!string.IsNullOrWhiteSpace(trackingNumber))
        {
            Navigation.NavigateTo($"/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
        }
    }

    private void HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            TrackShipment();
        }
    }
}

